5915       unsigned NumElts = VecTy->getNumElements();
5916       DemandedVecElts = APInt::getAllOnes(NumElts);
5917       auto *CIdx = dyn_cast<ConstantInt>(Op->getOperand(1));
5918       if (CIdx && CIdx->getValue().ult(NumElts))
5919         DemandedVecElts = APInt::getOneBitSet(NumElts, CIdx->getZExtValue());
5920     } else {
5921       DemandedVecElts = APInt(1, 1);
5922     }
5923 
5924     return computeKnownFPClass(Vec, DemandedVecElts, InterestedClasses, Known,
5925                                Q, Depth + 1);
5926   }
5927   case Instruction::InsertElement: {
5928     if (isa<ScalableVectorType>(Op->getType()))
5929       return;
5930 
5931     const Value *Vec = Op->getOperand(0);
5932     const Value *Elt = Op->getOperand(1);
5933     auto *CIdx = dyn_cast<ConstantInt>(Op->getOperand(2));
5934     unsigned NumElts = DemandedElts.getBitWidth();
5935     APInt DemandedVecElts = DemandedElts;
5936     bool NeedsElt = true;
5937     // If we know the index we are inserting to, clear it from Vec check.
5938     if (CIdx && CIdx->getValue().ult(NumElts)) {
5939       DemandedVecElts.clearBit(CIdx->getZExtValue());
5940       NeedsElt = DemandedElts[CIdx->getZExtValue()];
5941     }
5942 
5943     // Do we demand the inserted element?
5944     if (NeedsElt) {
5945       computeKnownFPClass(Elt, Known, InterestedClasses, Q, Depth + 1);
5946       // If we don't know any bits, early out.
5947       if (Known.isUnknown())
5948         break;
5949     } else {
5950       Known.KnownFPClasses = fcNone;
5951     }
5952 
5953     // Do we need anymore elements from Vec?
5954     if (!DemandedVecElts.isZero()) {
5955       KnownFPClass Known2;
5956       computeKnownFPClass(Vec, DemandedVecElts, InterestedClasses, Known2, Q,
5957                           Depth + 1);
5958       Known |= Known2;
5959     }
5960 
5961     break;
5962   }
5963   case Instruction::ShuffleVector: {
5964     // Handle vector splat idiom
5965     if (Value *Splat = getSplatValue(V)) {
5966       computeKnownFPClass(Splat, Known, InterestedClasses, Q, Depth + 1);
5967       break;
5968     }
5969 
5970     // For undef elements, we don't know anything about the common state of
5971     // the shuffle result.
5972     APInt DemandedLHS, DemandedRHS;
5973     auto *Shuf = dyn_cast<ShuffleVectorInst>(Op);
5974     if (!Shuf || !getShuffleDemandedElts(Shuf, DemandedElts, DemandedLHS, DemandedRHS))
5975       return;
5976 
5977     if (!!DemandedLHS) {
5978       const Value *LHS = Shuf->getOperand(0);
5979       computeKnownFPClass(LHS, DemandedLHS, InterestedClasses, Known, Q,
5980                           Depth + 1);
5981 
5982       // If we don't know any bits, early out.
5983       if (Known.isUnknown())
5984         break;
5985     } else {
5986       Known.KnownFPClasses = fcNone;
5987     }
5988 
5989     if (!!DemandedRHS) {
5990       KnownFPClass Known2;
5991       const Value *RHS = Shuf->getOperand(1);
5992       computeKnownFPClass(RHS, DemandedRHS, InterestedClasses, Known2, Q,
5993                           Depth + 1);
5994       Known |= Known2;
5995     }
5996 
5997     break;
5998   }
5999   case Instruction::ExtractValue: {
6000     const ExtractValueInst *Extract = cast<ExtractValueInst>(Op);
6001     ArrayRef<unsigned> Indices = Extract->getIndices();
6002     const Value *Src = Extract->getAggregateOperand();
6003     if (isa<StructType>(Src->getType()) && Indices.size() == 1 &&
6004         Indices[0] == 0) {
6005       if (const auto *II = dyn_cast<IntrinsicInst>(Src)) {
6006         switch (II->getIntrinsicID()) {
6007         case Intrinsic::frexp: {
6008           Known.knownNot(fcSubnormal);
6009 
6010           KnownFPClass KnownSrc;
6011           computeKnownFPClass(II->getArgOperand(0), DemandedElts,
6012                               InterestedClasses, KnownSrc, Q, Depth + 1);
6013 
6014           const Function *F = cast<Instruction>(Op)->getFunction();
6015           const fltSemantics &FltSem =
6016               Op->getType()->getScalarType()->getFltSemantics();
6017 
6018           if (KnownSrc.isKnownNever(fcNegative))
6019             Known.knownNot(fcNegative);
6020           else {
6021             if (F &&
6022                 KnownSrc.isKnownNeverLogicalNegZero(F->getDenormalMode(FltSem)))
6023               Known.knownNot(fcNegZero);
6024             if (KnownSrc.isKnownNever(fcNegInf))
6025               Known.knownNot(fcNegInf);
6026           }
6027 
6028           if (KnownSrc.isKnownNever(fcPositive))
6029             Known.knownNot(fcPositive);
6030           else {
6031             if (F &&
6032                 KnownSrc.isKnownNeverLogicalPosZero(F->getDenormalMode(FltSem)))
6033               Known.knownNot(fcPosZero);
6034             if (KnownSrc.isKnownNever(fcPosInf))
6035               Known.knownNot(fcPosInf);
6036           }
6037 
6038           Known.propagateNaN(KnownSrc);
6039           return;
6040         }
6041         default:
6042           break;
6043         }
6044       }
6045     }
6046 
6047     computeKnownFPClass(Src, DemandedElts, InterestedClasses, Known, Q,
6048                         Depth + 1);
6049     break;
